// Bad: exposed internals
public class BankAccount {
    public double balance; // anyone can set to negative!
}

// Good: encapsulated
public class BankAccount {
    private double balance;

    public void deposit(double amount) {
        if (amount <= 0) throw new IllegalArgumentException("Must be positive");
        this.balance += amount;
    }

    public double getBalance() { return balance; }

    // No setBalance() — callers can't bypass business rules
}

interface Shape {
    double area();
}

class Circle implements Shape {
    private final double radius;
    Circle(double r) { this.radius = r; }
    @Override public double area() { return Math.PI * radius * radius; }
}

class Rectangle implements Shape {
    private final double w, h;
    Rectangle(double w, double h) { this.w = w; this.h = h; }
    @Override public double area() { return w * h; }
}

// Polymorphic call — no instanceof, no casting
List<Shape> shapes = List.of(new Circle(5), new Rectangle(3, 4));
shapes.forEach(s -> System.out.println(s.area()));
// 78.53...
// 12.0

// Interface: defines what, not how
interface Printable {
    void print();                          // must implement
    default void printTwice() {            // optional to override
        print(); print();
    }
}

// Abstract class: partial implementation
abstract class Vehicle {
    private final String plate;
    Vehicle(String plate) { this.plate = plate; }  // shared constructor
    abstract int maxSpeed();               // subclasses define this
    String info() { return plate + " @ " + maxSpeed() + "km/h"; } // shared
}

// A class can do both
class Car extends Vehicle implements Printable {
    Car(String p) { super(p); }
    @Override public int maxSpeed() { return 200; }
    @Override public void print() { System.out.println(info()); }
}

// Inheritance approach — fragile
class InstrumentedHashSet<E> extends HashSet<E> {
    private int addCount = 0;
    @Override public boolean add(E e) { addCount++; return super.add(e); }
    @Override public boolean addAll(Collection<? extends E> c) {
        addCount += c.size();
        return super.addAll(c);  // BUG: addAll calls add() internally, double-counts!
    }
}

// Composition approach — robust
class InstrumentedSet<E> implements Set<E> {
    private final Set<E> delegate;  // composed, not extended
    private int addCount = 0;

    InstrumentedSet(Set<E> s) { this.delegate = s; }

    @Override public boolean add(E e) { addCount++; return delegate.add(e); }
    @Override public boolean addAll(Collection<? extends E> c) {
        addCount += c.size();
        return delegate.addAll(c);  // delegate handles internals — no double count
    }
    public int getAddCount() { return addCount; }
    // ... forward remaining Set methods to delegate
}

// Violates SRP — one class does persistence AND email
class OrderService {
    void placeOrder(Order o) {
        database.save(o);                  // persistence concern
        emailClient.send(o.getEmail(), …); // notification concern
    }
}

// SRP: separate responsibilities
class OrderRepository { void save(Order o) { … } }
class OrderNotifier  { void notify(Order o) { … } }
class OrderService {
    OrderService(OrderRepository repo, OrderNotifier notifier) { … }
    void placeOrder(Order o) { repo.save(o); notifier.notify(o); }
}

// OCP: extend via polymorphism, don't modify OrderService
interface OrderNotifier { void notify(Order o); }
class EmailNotifier implements OrderNotifier { … }
class SmsNotifier   implements OrderNotifier { … }  // added without touching OrderService
